    39→function AppShell() {
    40→  const [activeModule, setActiveModule] = useState<Module>('dashboard');
    41→  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
    42→
    43→  const renderModule = () => {
    44→    switch (activeModule) {
    45→      case 'dashboard':       return <Dashboard setModule={setActiveModule} />;
    46→      case 'projects':        return <Projects />;
    47→      case 'invoicing':       return <Invoicing />;
    48→      case 'accounting':      return <Accounting />;
    49→      case 'procurement':     return <Procurement />;
    50→      case 'rams':            return <RAMS />;
    51→      case 'cis':             return <CIS />;
    52→      case 'site-ops':        return <SiteOperations />;
    53→      case 'teams':           return <Teams />;
    54→      case 'tenders':         return <Tenders />;
    55→      case 'analytics':       return <Analytics />;
    56→      case 'safety':          return <Safety />;
    57→      case 'field-view':      return <FieldView />;
    58→      case 'crm':             return <CRM />;
    59→      case 'documents':       return <Documents />;
    60→      case 'timesheets':      return <Timesheets />;
    61→      case 'plant':           return <PlantEquipment />;
    62→      case 'subcontractors':  return <Subcontractors />;
    63→      case 'ai-assistant':    return <AIAssistant />;
    64→      case 'rfis':            return <RFIs />;
    65→      case 'change-orders':   return <ChangeOrders />;
    66→      case 'punch-list':      return <PunchList />;
    67→      case 'inspections':     return <Inspections />;
    68→      case 'risk-register':   return <RiskRegister />;
    69→      case 'drawings':        return <Drawings />;
    70→      case 'meetings':        return <Meetings />;
    71→      case 'materials':       return <Materials />;
    72→      case 'daily-reports':   return <DailyReports />;
    73→      case 'marketplace':     return <Marketplace />;
    74→      case 'settings':        return <Settings />;
    75→      default:                return <Dashboard setModule={setActiveModule} />;
    76→    }
    77→  };
    78→
    79→  return (
    80→    <div className="flex h-screen bg-gray-950 overflow-hidden">
    81→      <Sidebar
    82→        activeModule={activeModule}
    83→        setModule={setActiveModule}
    84→        collapsed={sidebarCollapsed}
    85→        setCollapsed={setSidebarCollapsed}
    86→      />
    87→      <div className="flex flex-col flex-1 overflow-hidden min-w-0">
    88→        <Header
    89→          activeModule={activeModule}
    90→          onMenuToggle={() => setSidebarCollapsed(!sidebarCollapsed)}
    91→        />
