    19→const MONTH_ABBR = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    20→
    21→function buildChartData(invoices: AnyRow[]) {
    22→  const now = new Date();
    23→  const months: { month: string; revenue: number; profit: number }[] = [];
    24→  for (let i = 5; i >= 0; i--) {
    25→    const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
    26→    months.push({ month: MONTH_ABBR[d.getMonth()], revenue: 0, profit: 0 });
    27→  }
    28→  invoices.filter(inv => inv.status === 'paid').forEach(inv => {
    29→    const dateStr = String(inv.issueDate ?? inv.issue_date ?? '');
    30→    if (!dateStr) return;
    31→    const d = new Date(dateStr);
    32→    const mIdx = months.findIndex(m => m.month === MONTH_ABBR[d.getMonth()] && d.getFullYear() === new Date().getFullYear());
    33→    if (mIdx !== -1) {
    34→      months[mIdx].revenue += Number(inv.amount ?? 0);
    35→      months[mIdx].profit  += Number(inv.amount ?? 0) * 0.23;
    36→    }
    37→  });
    38→  return months;
    39→}
